SELECT i.order_id, i.user_id, u.name AS username, s.service_name, s.service_describe, i.reason, i.create_time, i.update_time, i.manage_status FROM item i JOIN user u ON i.user_id = u.id JOIN services s ON i.service_id = s.service_id WHERE i.user_id = #{userId}
AND i.manage_status = #{manageStatus}
AND s.service_name LIKE CONCAT('%', #{serviceName}, '%')
ORDER BY i.create_time DESC
